import React, { useState, useEffect } from 'react';

export default function VerifiedSolutions() {
  const [solutions, setSolutions] = useState([]);
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(true);

  // University Brand Colors
  const gbpuatGreen = "#004d40";
  const gbpuatGold = "#ffc107";

  useEffect(() => {
    // Fetch joined questions and answers from backend
    fetch('http://localhost/farmer-portal-backend/get_resolved_qa.php')
      .then(res => res.json())
      .then(data => {
        setSolutions(data);
        setLoading(false);
      })
      .catch(err => {
        console.error("Error reading resolved stream:", err);
        setLoading(false);
      });
  }, []);

  const filteredSolutions = solutions.filter(item => 
    item.question_text.toLowerCase().includes(search.toLowerCase()) ||
    item.category.toLowerCase().includes(search.toLowerCase())
  );

  if (loading) return <p style={{ padding: '20px' }}>Loading official solutions archive...</p>;

  return (
    <div style={{ padding: '20px', maxWidth: '1000px', margin: '0 auto', fontFamily: 'Arial, sans-serif' }}>
      <h2 style={{ color: gbpuatGreen, marginBottom: '5px' }}>🏛️ University Verified Advisories & FAQ Database</h2>
      <p style={{ color: '#555', marginBottom: '20px' }}>Browse treatment blueprints and advice directly provided by Pantnagar scientists.</p>
      
      <input 
        type="text" 
        placeholder="🔍 Type keywords to filter solutions (e.g., Wheat, Blight, Fertilizer)..." 
        value={search}
        onChange={(e) => setSearch(e.target.value)}
        style={{ width: '100%', padding: '12px', boxSizing: 'border-box', border: `2px solid ${gbpuatGreen}`, borderRadius: '6px', fontSize: '1em', marginBottom: '25px' }}
      />

      {filteredSolutions.length === 0 ? (
        <p style={{ fontStyle: 'italic', color: '#888' }}>No completed solutions match that query text at the moment.</p>
      ) : (
        <div style={{ display: 'grid', gap: '25px' }}>
          {filteredSolutions.map((pair, index) => (
            <div key={index} style={{ border: '1px solid #ddd', borderRadius: '8px', overflow: 'hidden', boxShadow: '0 2px 5px rgba(0,0,0,0.05)' }}>
              
              {/* Question Shell Container */}
              <div style={{ backgroundColor: '#fdfdfd', padding: '15px 20px', borderBottom: '1px solid #eee' }}>
                <div style={{ display: 'flex', gap: '15px', fontSize: '0.85em', color: '#666', marginBottom: '6px' }}>
                  <span>🌾 Category: <b>{pair.category}</b></span>
                  <span>📍 Location: {pair.location}</span>
                  <span style={{ marginLeft: 'auto' }}>Asked by: {pair.farmer_name}</span>
                </div>
                <p style={{ margin: 0, fontWeight: 'bold', color: '#333' }}>"Question: {pair.question_text}"</p>
              </div>

              {/* Verified Solution Container */}
              <div style={{ backgroundColor: '#f4fbf7', padding: '15px 20px', borderLeft: `6px solid ${gbpuatGreen}` }}>
                <div style={{ fontSize: '0.85em', color: '#2e7d32', fontWeight: 'bold', marginBottom: '5px' }}>
                  🎓 Verified University Treatment via {pair.expert_name}:
                </div>
                <p style={{ margin: 0, color: '#1b5e20', lineHeight: '1.5', whiteSpace: 'pre-line' }}>
                  {pair.solution_text}
                </p>
                <div style={{ textAlign: 'right', fontSize: '0.75em', color: '#777', marginTop: '10px' }}>
                  Advisory Date: {new Date(pair.replied_at).toLocaleDateString()}
                </div>
              </div>

            </div>
          ))}
        </div>
      )}
    </div>
  );
}
